def toml_quoted_key(value: str) -> str:
    return value.replace("\\", "\\\\").replace('"', '\\"')


def mcp_oauth_credential_key(name: str, url: str) -> str:
    payload = json.dumps(
        {"headers": {}, "type": "http", "url": url},
        separators=(",", ":"),
        sort_keys=True,
    )
    return f"{name}|{hashlib.sha256(payload.encode()).hexdigest()[:16]}"


def unused_tcp_port() -> int:
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as probe:
        probe.bind(("127.0.0.1", 0))
        return int(probe.getsockname()[1])


def seed_memory_state_db(codex_home: Path) -> Path:
    db_path = codex_home / "state_5.sqlite"
    with sqlite3.connect(db_path) as db:
        db.executescript(
            """
            CREATE TABLE stage1_outputs (thread_id TEXT PRIMARY KEY, raw_memory TEXT);
            CREATE TABLE jobs (kind TEXT, job_key TEXT, status TEXT);
            INSERT INTO stage1_outputs (thread_id, raw_memory)
            VALUES ('thread-1', 'raw memory');
            INSERT INTO jobs (kind, job_key, status)
            VALUES
                ('memory_stage1', 'thread-1', 'completed'),
                ('memory_consolidate_global', 'global', 'completed'),
                ('unrelated', 'keep', 'completed');
            """
        )
    return db_path


def seed_feedback_logs_db(
    codex_home: Path,
    rows: list[tuple[int, int, str, str, str | None, str | None]],
) -> Path:
    db_path = codex_home / "logs_2.sqlite"
    with sqlite3.connect(db_path) as db:
        db.executescript(
            """
            DROP TABLE IF EXISTS logs;
            CREATE TABLE logs (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                ts INTEGER NOT NULL,
                ts_nanos INTEGER NOT NULL,
                level TEXT NOT NULL,
                target TEXT NOT NULL,
                feedback_log_body TEXT,
                module_path TEXT,
                file TEXT,
                line INTEGER,
                thread_id TEXT,
                process_uuid TEXT,
                estimated_bytes INTEGER NOT NULL DEFAULT 0
            );
            """
        )
        db.executemany(
            """
            INSERT INTO logs (
                ts, ts_nanos, level, target, feedback_log_body,
                thread_id, process_uuid, estimated_bytes
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            """,
            [
                (
                    ts,
                    ts_nanos,
                    level,
                    "cli",
                    body,
                    thread_id,
                    process_uuid,
                    len(body or "") + len(level) + len("cli"),
                )
                for ts, ts_nanos, level, body, thread_id, process_uuid in rows
            ],
        )
    return db_path


def seed_feedback_state_db(
    codex_home: Path,
    threads: list[tuple[str, Path]],
    edges: list[tuple[str, str, str]],
) -> Path:
    db_path = codex_home / "state_5.sqlite"
    with sqlite3.connect(db_path) as db:
        db.executescript(
            """
            DROP TABLE IF EXISTS threads;
            DROP TABLE IF EXISTS thread_spawn_edges;
            CREATE TABLE threads (
                id TEXT PRIMARY KEY,
                rollout_path TEXT NOT NULL,
                created_at INTEGER NOT NULL DEFAULT 0,
                updated_at INTEGER NOT NULL DEFAULT 0,
                created_at_ms INTEGER,
                updated_at_ms INTEGER,
                source TEXT NOT NULL DEFAULT 'cli',
                thread_source TEXT,
                agent_nickname TEXT,
                agent_role TEXT,
                agent_path TEXT,
                model_provider TEXT NOT NULL DEFAULT 'openai',
                model TEXT,
                reasoning_effort TEXT,
                cwd TEXT NOT NULL DEFAULT '/',
                cli_version TEXT NOT NULL DEFAULT '0.0.0',
                title TEXT NOT NULL DEFAULT '',
                sandbox_policy TEXT NOT NULL DEFAULT 'danger-full-access',
                approval_mode TEXT NOT NULL DEFAULT 'never',
                tokens_used INTEGER NOT NULL DEFAULT 0,
                first_user_message TEXT NOT NULL DEFAULT '',
                archived INTEGER NOT NULL DEFAULT 0,
                archived_at INTEGER,
                memory_mode TEXT NOT NULL DEFAULT 'enabled',
                git_sha TEXT,
                git_branch TEXT,
                git_origin_url TEXT
            );
            CREATE TABLE thread_spawn_edges (
                parent_thread_id TEXT NOT NULL,
                child_thread_id TEXT NOT NULL PRIMARY KEY,
                status TEXT NOT NULL
            );
            """
        )
        db.executemany(
            "INSERT INTO threads (id, rollout_path) VALUES (?, ?)",
            [(thread_id, str(path)) for thread_id, path in threads],
        )
        db.executemany(
            """
            INSERT INTO thread_spawn_edges (parent_thread_id, child_thread_id, status)
            VALUES (?, ?, ?)
            """,
            edges,
        )
    return db_path


def sqlite_count(db_path: Path, query: str) -> int:
    with sqlite3.connect(db_path) as db:
        row = db.execute(query).fetchone()
    assert row is not None
    return int(row[0])


def sqlite_row(db_path: Path, query: str, params: tuple[object, ...]) -> tuple[object, ...]:
    with sqlite3.connect(db_path) as db:
        row = db.execute(query, params).fetchone()
    assert row is not None
    return tuple(row)


def remote_plugin_bundle_bytes() -> bytes:
    out = io.BytesIO()
    with tarfile.open(fileobj=out, mode="w:gz") as tar:
        for name, data in {
            "linear/.codex-plugin/plugin.json": json.dumps(
                {"name": "linear", "version": "1.2.3"},
                separators=(",", ":"),
            ).encode("utf-8"),
            "linear/skills/plan-work/SKILL.md": b"# Plan Work\n",
        }.items():
            info = tarfile.TarInfo(name)
            info.size = len(data)
            info.mtime = 0
            info.mode = 0o644
            tar.addfile(info, io.BytesIO(data))
    return out.getvalue()


