        close_server(trusted_rules_proc)
        trusted_rules_proc = None

        (untrusted_rules_project / ".codex" / "rules").mkdir(parents=True)
        untrusted_rules_path = untrusted_rules_project / ".codex" / "rules" / "broken.rules"
