def wait_for_websocket_bind(proc: subprocess.Popen[str], timeout: float) -> tuple[str, int]:
    assert proc.stderr is not None
    deadline = time.monotonic() + timeout
    while time.monotonic() < deadline:
        if proc.poll() is not None:
            raise AssertionError(f"app-server exited before websocket bind: {proc.stderr.read()}")
        remaining = max(0.0, deadline - time.monotonic())
        ready, _, _ = select.select([proc.stderr], [], [], min(remaining, 0.05))
        if not ready:
            continue
        line = proc.stderr.readline()
        if line:
            for token in line.split():
                if not token.startswith("ws://"):
                    continue
                host, port_text = token.removeprefix("ws://").rsplit(":", 1)
                return host, int(port_text)
    raise AssertionError("timed out waiting for websocket bind address")


def websocket_http_status(host: str, port: int, path: str) -> int:
    with socket.create_connection((host, port), timeout=5) as client:
        client.sendall(
            f"GET {path} HTTP/1.1\r\nHost: {host}:{port}\r\nConnection: close\r\n\r\n".encode(
                "ascii"
            )
        )
        data = b""
        while b"\r\n\r\n" not in data:
            chunk = client.recv(4096)
            if not chunk:
                break
            data += chunk
        status_line = data.split(b"\r\n", 1)[0].decode("ascii")
        return int(status_line.split()[1])


def websocket_handshake_status(host: str, port: int, headers: list[str]) -> int:
    request = "\r\n".join(
        [
            "GET / HTTP/1.1",
            f"Host: {host}:{port}",
            *headers,
            "",
            "",
        ]
    ).encode("ascii")
    with socket.create_connection((host, port), timeout=5) as client:
        client.sendall(request)
        data = b""
        while b"\r\n\r\n" not in data:
            chunk = client.recv(4096)
            if not chunk:
                break
            data += chunk
        status_line = data.split(b"\r\n", 1)[0].decode("ascii")
        return int(status_line.split()[1])


def websocket_signed_bearer_token(secret: bytes, claims: dict) -> str:
    def encode(data: bytes) -> str:
        return base64.urlsafe_b64encode(data).rstrip(b"=").decode("ascii")

    header = encode(b'{"alg":"HS256","typ":"JWT"}')
    payload = encode(json.dumps(claims, separators=(",", ":")).encode("utf-8"))
    signing_input = f"{header}.{payload}"
    signature = encode(hmac.new(secret, signing_input.encode("ascii"), hashlib.sha256).digest())
    return f"{signing_input}.{signature}"


class SmokeWebSocket:
    def __init__(self, host: str, port: int, bearer_token: str | None = None) -> None:
        self.sock = socket.create_connection((host, port), timeout=5)
        key = base64.b64encode(os.urandom(16)).decode("ascii")
        auth_header = f"Authorization: Bearer {bearer_token}\r\n" if bearer_token is not None else ""
        self.sock.sendall(
            (
                f"GET / HTTP/1.1\r\n"
                f"Host: {host}:{port}\r\n"
                "Upgrade: websocket\r\n"
                "Connection: Upgrade\r\n"
                f"Sec-WebSocket-Key: {key}\r\n"
                "Sec-WebSocket-Version: 13\r\n"
                f"{auth_header}"
                "\r\n"
            ).encode("ascii")
        )
        response = self._recv_until(b"\r\n\r\n")
        status_line = response.split(b"\r\n", 1)[0]
        if b" 101 " not in status_line:
            raise AssertionError(f"websocket handshake failed: {response!r}")
        response_lower = response.lower()
        if b"connection: upgrade" not in response_lower:
            raise AssertionError(f"websocket handshake missing upgrade connection: {response!r}")
        if b"connection: close" in response_lower:
            raise AssertionError(f"websocket handshake should not close connection: {response!r}")
        expected_accept = base64.b64encode(
            hashlib.sha1((key + "258EAFA5-E914-47DA-95CA-C5AB0DC85B11").encode("ascii")).digest()
        ).decode("ascii")
        expected_header = f"sec-websocket-accept: {expected_accept}".lower().encode("ascii")
        if expected_header not in response_lower:
            raise AssertionError(f"websocket accept mismatch: {response!r}")

    def close(self) -> None:
        try:
            self._send_frame(0x8, b"")
        finally:
            self.sock.close()

    def write_json(self, payload: dict) -> None:
        self._send_frame(0x1, json.dumps(payload, separators=(",", ":")).encode("utf-8"))

    def read_json(self) -> dict:
        payload = self._read_frame()
        if payload is None:
            raise AssertionError("websocket closed before response")
        return json.loads(payload.decode("utf-8"))

    def _recv_until(self, delimiter: bytes) -> bytes:
        data = b""
        while delimiter not in data:
            chunk = self.sock.recv(4096)
            if not chunk:
                break
            data += chunk
        return data

    def _recv_exact(self, size: int) -> bytes:
        data = b""
        while len(data) < size:
            chunk = self.sock.recv(size - len(data))
            if not chunk:
                raise AssertionError("websocket closed unexpectedly")
            data += chunk
        return data

    def _send_frame(self, opcode: int, payload: bytes) -> None:
        header = bytearray([0x80 | opcode])
        if len(payload) <= 125:
            header.append(0x80 | len(payload))
        elif len(payload) <= 0xFFFF:
            header.append(0x80 | 126)
            header.extend(len(payload).to_bytes(2, "big"))
        else:
            header.append(0x80 | 127)
            header.extend(len(payload).to_bytes(8, "big"))
        mask = os.urandom(4)
        masked = bytes(byte ^ mask[index % 4] for index, byte in enumerate(payload))
        self.sock.sendall(bytes(header) + mask + masked)

    def _read_frame(self) -> bytes | None:
        first, second = self._recv_exact(2)
        opcode = first & 0x0F
        length = second & 0x7F
        if length == 126:
            length = int.from_bytes(self._recv_exact(2), "big")
        elif length == 127:
            length = int.from_bytes(self._recv_exact(8), "big")
        masked = (second & 0x80) != 0
        mask = self._recv_exact(4) if masked else b""
        payload = self._recv_exact(length)
        if masked:
            payload = bytes(byte ^ mask[index % 4] for index, byte in enumerate(payload))
        if opcode == 0x8:
            return None
        if opcode != 0x1:
            raise AssertionError(f"unexpected websocket opcode {opcode}")
        return payload


def exercise_websocket_initialize(host: str, port: int, bearer_token: str | None = None) -> None:
    websocket = SmokeWebSocket(host, port, bearer_token)
    try:
        websocket.write_json(
            {
                "jsonrpc": "2.0",
                "id": "second-websocket-initialize",
                "method": "initialize",
                "params": {
                    "clientInfo": {
                        "name": "app-server-smoke",
                        "version": "0",
                    },
                    "capabilities": {},
                },
            }
        )
        initialize = websocket.read_json()
        assert initialize["id"] == "second-websocket-initialize"
        assert initialize["result"]["serverInfo"]["name"] == "codex-zig-app-server"
    finally:
        websocket.close()


def exercise_websocket_connection_state_reset(host: str, port: int, bearer_token: str | None = None) -> None:
    websocket = SmokeWebSocket(host, port, bearer_token)
    try:
        websocket.write_json(
            {
                "jsonrpc": "2.0",
                "id": "websocket-reset-initialize-first",
                "method": "initialize",
                "params": {
                    "clientInfo": {
                        "name": "app-server-smoke",
                        "version": "0",
                    },
                    "capabilities": {},
                },
            }
        )
        initialize = websocket.read_json()
        assert initialize["id"] == "websocket-reset-initialize-first"
        websocket.write_json(
            {
                "jsonrpc": "2.0",
                "id": "websocket-reset-thread-start",
                "method": "thread/start",
                "params": {"ephemeral": True},
            }
        )
        thread_start = websocket.read_json()
        assert thread_start["id"] == "websocket-reset-thread-start"
        thread_id = thread_start["result"]["thread"]["id"]
        started = websocket.read_json()
        assert started["method"] == "thread/started"
        assert started["params"]["thread"]["id"] == thread_id
    finally:
        websocket.close()

    websocket = SmokeWebSocket(host, port, bearer_token)
    try:
        websocket.write_json(
            {
                "jsonrpc": "2.0",
                "id": "websocket-reset-initialize-second",
                "method": "initialize",
                "params": {
                    "clientInfo": {
                        "name": "app-server-smoke",
                        "version": "0",
                    },
                    "capabilities": EXPERIMENTAL_API_CAPABILITIES,
                },
            }
        )
        initialize = websocket.read_json()
        assert initialize["id"] == "websocket-reset-initialize-second"
        websocket.write_json(
            {
                "jsonrpc": "2.0",
                "id": "websocket-reset-thread-read",
                "method": "thread/read",
                "params": {"threadId": thread_id, "includeTurns": False},
            }
        )
        thread_read = websocket.read_json()
        assert thread_read["id"] == "websocket-reset-thread-read"
        assert thread_read["result"]["thread"]["id"] == thread_id
        websocket.write_json(
            {
                "jsonrpc": "2.0",
                "id": "websocket-reset-unsubscribe",
                "method": "thread/unsubscribe",
                "params": {"threadId": thread_id},
            }
        )
        unsubscribe = websocket.read_json()
        assert unsubscribe["id"] == "websocket-reset-unsubscribe"
        assert unsubscribe["result"] == {"status": "notSubscribed"}
        websocket.write_json(
            {
                "jsonrpc": "2.0",
                "id": "websocket-process-spawn-stdio-only",
                "method": "process/spawn",
                "params": {
                    "command": [sys.executable, "-c", "import sys; sys.stdin.read()"],
                    "processHandle": "websocket-proc-stdio-only",
                    "cwd": tempfile.gettempdir(),
                    "streamStdin": True,
                },
            }
        )
        process_spawn = websocket.read_json()
        assert process_spawn["id"] == "websocket-process-spawn-stdio-only"
        assert process_spawn["error"]["code"] == -32603
        assert "stdio app-server transport only" in process_spawn["error"]["message"]
    finally:
        websocket.close()


def run_websocket_smoke(binary: Path) -> None:
    codex_home = Path(tempfile.mkdtemp(prefix="codex-zig-ws-home-", dir="/tmp"))
    env = os.environ.copy()
    env["CODEX_HOME"] = str(codex_home)
    proc = subprocess.Popen(
        [str(binary), "app-server", "--listen", "ws://127.0.0.1:0"],
        stdin=subprocess.DEVNULL,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        text=True,
        env=env,
    )
    websocket = None
    try:
        host, port = wait_for_websocket_bind(proc, 5)
        assert websocket_http_status(host, port, "/readyz") == 200
        assert websocket_http_status(host, port, "/healthz") == 200
        bad_key = base64.b64encode(os.urandom(16)).decode("ascii")
        assert (
            websocket_handshake_status(
                host,
                port,
                [
                    "Connection: Upgrade",
                    f"Sec-WebSocket-Key: {bad_key}",
                    "Sec-WebSocket-Version: 13",
                ],
            )
            == 400
        )
        websocket = SmokeWebSocket(host, port)
        exercise_json_rpc(websocket.write_json, websocket.read_json)
        websocket.close()
        websocket = None
        if proc.poll() is not None:
            raise AssertionError(f"app-server exited after first websocket client: {proc.stderr.read()}")
        exercise_websocket_initialize(host, port)
        if proc.poll() is not None:
            raise AssertionError(f"app-server exited after second websocket client: {proc.stderr.read()}")
        exercise_websocket_connection_state_reset(host, port)
        if proc.poll() is not None:
            raise AssertionError(f"app-server exited after websocket connection-state reset smoke: {proc.stderr.read()}")
    finally:
        if websocket is not None:
            websocket.close()
        if proc.poll() is None:
            proc.kill()
            proc.wait(timeout=5)
        shutil.rmtree(codex_home, ignore_errors=True)


